module watchdog_timer (  
    input wire clk,  
    input wire reset,  
    input wire enable,  
    input wire system_ok,  
    output reg timeout  
);  
    reg [2:0] watchdog_counter; // 3-bit watchdog_counter for up to 7 cycles  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            watchdog_counter <= 3'b000;  
            timeout <= 0;  
        end else if (enable) begin  
            if (!system_ok) begin  
                watchdog_counter <= watchdog_counter + 1;  
                if (watchdog_counter == 3'b101) // 5 cycles  
                    timeout <= 1;  
            end else begin  
                watchdog_counter <= 3'b000;  
                timeout <= 0;  
            end  
        end  
    end  
endmodule
